def organize_medieval_items(items):  
    organized = {}  
    for item in items:  
        first_letter = item[0].lower()  
        if first_letter not in organized:  
            organized[first_letter] = []  
        organized[first_letter].append(item)  
    for key in organized:  
        organized[key].sort()  
    return organized  

